INSERT INTO `ec_purchase_order_config` VALUES (1,'鍞崄鍢夐噰璐崟','鍦板潃锛氭睍澶村競婢勬捣鍖鸿幉涓嬮晣涓滄咕鏂囧寲鍏洯','TEL锛?8819446360','[\"鍑鸿揣鏃堕棿銆佹棩鏈熶笉鑳藉啀鎷栧悗锛佷骇鍝佸繀椤婚€氳繃缇庡浗绔欏叏妫€娴嬩互鍙奀PSIA锛孋PC妫€娴嬨€俓",\"澶ц揣浜у搧棰滆壊蹇呴』璺熷乏涓婅鍥剧墖涓€鏍凤紝涓嶈兘鏇存敼銆俓",\"鎸夋柊绾哥瑙勬牸鍖呰锛岀‘淇濊揣鐗╃ǔ鍥猴紝杩愯緭杩囩▼涓笉浼氱牬鎹熴€俓"]','[\"鏈崟涓洪噰璐悎鍚岋紝璇峰伐鍘傜瀛楃洊绔犲洖浼狅紝骞跺Ε鍠勪繚绠°€俓",\"浜у搧鍚嶇О蹇呴』涓庨噰璐崟涓€鑷达紝濡傛湁鍙樻洿璇锋彁鍓嶆矡閫氱‘璁ゃ€俓",\"璇锋寜绾﹀畾鏃堕棿浜よ揣锛屽鏈夊欢璇绗竴鏃堕棿閫氱煡鎴戝徃銆俓",\"璐ф涓庡彂璐т簨瀹滆涓庨噰璐仈绯讳汉鏍稿鍚庢墽琛屻€俓"]','寮犲皬濮?,'18819446360','寮犲皬濮?,'18819446360','瑙佷笂闈㈠湴鍧€','','2026-06-27 21:59:44');
